SELECT AVG(amount) AS average_gold_points
FROM gold_points_transactions
WHERE transaction_type = 'earned';

SELECT player_id, player_name
FROM players
WHERE current_gear_needed < 100 AND gp > 0;

SELECT gear_type, COUNT(*) 
FROM gear_requirements 
GROUP BY gear_type;

SELECT AVG(character_count) as average_characters_per_player
FROM (
  SELECT player_id, COUNT(character_id) as character_count
  FROM characters
  GROUP BY player_id
);
